ListEmptyFactory={}function ListEmptyFactory:getListEmptyImage(a)local b=ThemedImage("Icon_nft_status_empty")if CompatibleBridge.isModeLite and CompatibleBridge:isModeLite()then b=PlainImage("lite_earn_segment_empty")end;if a==nil then return b end;if a==ListPageSource.PERSONAL_MY_CREATED or a==ListPageSource.PERSONAL_COLLECTED or a==ListPageSource.PERSONAL_COLLECTION_VIEW or a==ListPageSource.PERSONAL_HIDDEN or a==ListPageSource.PERSONAL_FAVORITE then return ThemedImage("icon_nft_personal_center_empty")end;if a==ListPageSource.OFFER then return ThemedImage("icon_nft_order_no_data")end;if a==ListPageSource.SEARCH then return ThemedImage("Icon_nft_status_empty")end;if a<1000 then return ThemedImage("Icon_nft_search_empty")end;if a>1000 and a<2000 then return ThemedImage("Icon_nft_offer_empty")end;return b end
